mapper.select:
select 
from articles
where source_id = #{sourceId}
  and concept_id = #{conceptId}

mapper.update:
update articles
set metadata_json = jsonb_set(
    coalesce(metadata_json::jsonb, '{}'::jsonb),
    '{upstream_corrections}',
    (
        select coalesce(jsonb_agg(elem), '[]'::jsonb)
        from jsonb_array_elements(coalesce(metadata_json::jsonb->'upstream_corrections', '[]'::jsonb)) as elem
        where elem->>'from' <> #{fromConceptId}
    )
),
    updated_at = CURRENT_TIMESTAMP
where concept_id = #{downstreamConceptId}

update articles
set is_hotspot = true,
    requires_result_verification = true,
    risk_level = case
        when lower(risk_level) = 'high' then risk_level
        else 'medium'
    end,
    risk_reasons = case
        when #{riskReason} = any(risk_reasons) then risk_reasons
        else array_append(risk_reasons, #{riskReason})
    end,
    updated_at = CURRENT_TIMESTAMP
where article_key = any(
    #{articleKeys,typeHandler=com.xbk.lattice.infra.persistence.mybatis.StringListArrayTypeHandler}
)
